import { describe, expect, it } from 'vitest'
import {
  applyMove,
  createInitialGame,
  hasAvailableMoves,
  spawnRandomTile,
} from './logic'
import type { Board, SpawnRandom } from './types'

const emptyBoard = (): Board => Array.from({ length: 4 }, () => Array(4).fill(null))

describe('2048 game logic', () => {
  it('creates a 4x4 board with two starting tiles and zero score', () => {
    const game = createInitialGame([
      { index: 0, value: 2 },
      { index: 5, value: 4 },
    ])

    expect(game.board).toHaveLength(4)
    expect(game.board.every((row) => row).length).toBe(4)
    expect(game.board.flat().filter(Boolean)).toHaveLength(2)
    expect(game.board[0][0]).toBe(2)
    expect(game.board[1][1]).toBe(4)
    expect(game.score).toBe(0)
    expect(game.won).toBe(false)
    expect(game.gameOver).toBe(false)
  })

  it('slides and merges left once per pair and updates score', () => {
    const board: Board = [
      [2, null, 2, 2],
      [null, null, null, null],
      [null, null, null, null],
      [null, null, null, null],
    ]

    const result = applyMove(board, 'left')

    expect(result.board[0]).toEqual([4, 2, null, null])
    expect(result.scoreGained).toBe(4)
    expect(result.moved).toBe(true)
  })

  it('prevents a double merge in one move', () => {
    const board: Board = [
      [2, 2, 2, 2],
      [null, null, null, null],
      [null, null, null, null],
      [null, null, null, null],
    ]

    const result = applyMove(board, 'left')

    expect(result.board[0]).toEqual([4, 4, null, null])
    expect(result.scoreGained).toBe(8)
  })

  it('spawns a tile into an empty cell with the provided random descriptor', () => {
    const board = emptyBoard()
    const spawn: SpawnRandom = { index: 6, value: 4 }

    const next = spawnRandomTile(board, spawn)

    expect(next[1][2]).toBe(4)
    expect(next.flat().filter(Boolean)).toHaveLength(1)
  })

  it('detects a win when a 2048 tile is created', () => {
    const board: Board = [
      [1024, 1024, null, null],
      [null, null, null, null],
      [null, null, null, null],
      [null, null, null, null],
    ]

    const result = applyMove(board, 'left')

    expect(result.board[0][0]).toBe(2048)
    expect(result.won).toBe(true)
  })

  it('detects when moves remain and when the game is over', () => {
    const playable: Board = [
      [2, 4, 8, 16],
      [32, 64, 128, 256],
      [512, 1024, 2, 2],
      [4, 8, 16, 32],
    ]
    const stuck: Board = [
      [2, 4, 8, 16],
      [32, 64, 128, 256],
      [512, 1024, 2, 4],
      [4, 8, 16, 32],
    ]

    expect(hasAvailableMoves(playable)).toBe(true)
    expect(hasAvailableMoves(stuck)).toBe(false)
    expect(applyMove(stuck, 'left').gameOver).toBe(true)
  })

  it('creates deterministic initial games from queued spawns', () => {
    const game = createInitialGame([
      { index: 15, value: 2 },
      { index: 14, value: 2 },
    ])

    expect(game.board[3][3]).toBe(2)
    expect(game.board[3][2]).toBe(2)
  })
})

import { BOARD_SIZE } from './types'
import type { Board, Direction, GameSnapshot, MoveResult, SpawnRandom } from './types'

const cloneBoard = (board: Board): Board => board.map((row) => [...row])

const createEmptyBoard = (): Board =>
  Array.from({ length: BOARD_SIZE }, () => Array(BOARD_SIZE).fill(null))

export const getEmptyCellIndices = (board: Board): number[] =>
  board.flatMap((value, rowIndex) =>
    value.flatMap((cell, columnIndex) => (cell === null ? [rowIndex * BOARD_SIZE + columnIndex] : [])),
  )

const has2048 = (board: Board): boolean => board.some((row) => row.some((cell) => (cell ?? 0) >= 2048))

export const hasAvailableMoves = (board: Board): boolean => {
  if (getEmptyCellIndices(board).length > 0) {
    return true
  }

  for (let row = 0; row < BOARD_SIZE; row += 1) {
    for (let column = 0; column < BOARD_SIZE; column += 1) {
      const value = board[row][column]
      if (row + 1 < BOARD_SIZE && board[row + 1][column] === value) {
        return true
      }
      if (column + 1 < BOARD_SIZE && board[row][column + 1] === value) {
        return true
      }
    }
  }

  return false
}

const pickRandomSpawn = (board: Board): SpawnRandom | null => {
  const empty = getEmptyCellIndices(board)
  if (empty.length === 0) {
    return null
  }

  const index = empty[Math.floor(Math.random() * empty.length)]
  const value: 2 | 4 = Math.random() < 0.9 ? 2 : 4
  return { index, value }
}

export const spawnRandomTile = (board: Board, spawn: SpawnRandom | null = pickRandomSpawn(board)): Board => {
  if (!spawn) {
    return cloneBoard(board)
  }

  const next = cloneBoard(board)
  const row = Math.floor(spawn.index / BOARD_SIZE)
  const column = spawn.index % BOARD_SIZE

  if (next[row][column] !== null) {
    return next
  }

  next[row][column] = spawn.value
  return next
}

const slideAndMergeLine = (line: Array<number | null>) => {
  const values = line.filter((value): value is number => value !== null)
  const merged: Array<number | null> = []
  let scoreGained = 0

  for (let index = 0; index < values.length; index += 1) {
    const current = values[index]
    const next = values[index + 1]

    if (current === next) {
      const combined = current * 2
      merged.push(combined)
      scoreGained += combined
      index += 1
    } else {
      merged.push(current)
    }
  }

  while (merged.length < BOARD_SIZE) {
    merged.push(null)
  }

  return { line: merged, scoreGained }
}

const getLine = (board: Board, direction: Direction, index: number): Array<number | null> => {
  switch (direction) {
    case 'left':
      return [...board[index]]
    case 'right':
      return [...board[index]].reverse()
    case 'up':
      return board.map((row) => row[index])
    case 'down':
      return board.map((row) => row[index]).reverse()
  }
}

const setLine = (board: Board, direction: Direction, index: number, line: Array<number | null>) => {
  const resolved = direction === 'right' || direction === 'down' ? [...line].reverse() : line

  if (direction === 'left' || direction === 'right') {
    board[index] = resolved
    return
  }

  for (let row = 0; row < BOARD_SIZE; row += 1) {
    board[row][index] = resolved[row]
  }
}

export const applyMove = (board: Board, direction: Direction): MoveResult => {
  const next = createEmptyBoard()
  let scoreGained = 0

  for (let index = 0; index < BOARD_SIZE; index += 1) {
    const line = getLine(board, direction, index)
    const merged = slideAndMergeLine(line)
    setLine(next, direction, index, merged.line)
    scoreGained += merged.scoreGained
  }

  const moved = JSON.stringify(next) !== JSON.stringify(board)
  const won = has2048(next)
  const gameOver = !hasAvailableMoves(next)

  return { board: next, scoreGained, moved, won, gameOver }
}

export const createInitialGame = (spawns: SpawnRandom[] = []): GameSnapshot => {
  let board = createEmptyBoard()

  const first = spawns[0] ?? pickRandomSpawn(board)
  board = spawnRandomTile(board, first)

  const second = spawns[1] ?? pickRandomSpawn(board)
  board = spawnRandomTile(board, second)

  return {
    board,
    score: 0,
    won: false,
    gameOver: false,
  }
}

