import type { Board } from '../game/types'

const tileClassName = (value: number | null) => {
  if (value === null) return 'tile tile-empty'
  return `tile tile-${value}`
}

interface GameBoardProps {
  board: Board
}

export function GameBoard({ board }: GameBoardProps) {
  return (
    <div
      className="board"
      data-testid="board"
      role="grid"
      aria-label="2048 board"
    >
      {board.flatMap((row, rowIndex) =>
        row.map((value, columnIndex) => (
          <div
            key={`${rowIndex}-${columnIndex}`}
            className={tileClassName(value)}
            role="gridcell"
            aria-label={value === null ? 'empty cell' : `tile ${value}`}
          >
            {value ?? ''}
          </div>
        )),
      )}
    </div>
  )
}

import { useCallback, useEffect, useMemo, useState } from 'react'
import './App.css'
import { GameBoard } from './components/GameBoard'
import { ScorePanel } from './components/ScorePanel'
import { applyMove, createInitialGame, spawnRandomTile } from './game/logic'
import type { Direction, GameSnapshot } from './game/types'

const keyToDirection: Record<string, Direction> = {
  ArrowUp: 'up',
  ArrowDown: 'down',
  ArrowLeft: 'left',
  ArrowRight: 'right',
  w: 'up',
  a: 'left',
  s: 'down',
  d: 'right',
  W: 'up',
  A: 'left',
  S: 'down',
  D: 'right',
}

const statusFromState = (game: GameSnapshot) => {
  if (game.gameOver) return 'Game over'
  if (game.won) return 'You reached 2048!'
  return 'Keep going'
}

function App() {
  const [game, setGame] = useState<GameSnapshot>(() => createInitialGame())

  const restartGame = useCallback(() => {
    setGame(createInitialGame())
  }, [])

  const handleMove = useCallback((direction: Direction) => {
    setGame((current) => {
      if (current.gameOver) {
        return current
      }

      const moved = applyMove(current.board, direction)
      if (!moved.moved) {
        return {
          ...current,
          won: moved.won,
          gameOver: moved.gameOver,
        }
      }

      const boardWithSpawn = spawnRandomTile(moved.board)
      const won = moved.won || boardWithSpawn.some((row) => row.some((cell) => (cell ?? 0) >= 2048))
      const gameOver = moved.gameOver || !boardWithSpawn.some((row) => row.includes(null)) && !applyMove(boardWithSpawn, 'left').moved && !applyMove(boardWithSpawn, 'right').moved && !applyMove(boardWithSpawn, 'up').moved && !applyMove(boardWithSpawn, 'down').moved

      return {
        board: boardWithSpawn,
        score: current.score + moved.scoreGained,
        won,
        gameOver,
      }
    })
  }, [])

  useEffect(() => {
    const onKeyDown = (event: KeyboardEvent) => {
      const direction = keyToDirection[event.key]
      if (!direction) {
        return
      }
      event.preventDefault()
      handleMove(direction)
    }

    window.addEventListener('keydown', onKeyDown)
    return () => window.removeEventListener('keydown', onKeyDown)
  }, [handleMove])

  const status = useMemo(() => statusFromState(game), [game])

  return (
    <main className="app-shell">
      <section className="game-card">
        <header className="hero">
          <div>
            <p className="eyebrow">React + Vite + TypeScript</p>
            <h1>2048</h1>
            <p className="instructions">Use Arrow keys or WASD to combine tiles and chase 2048.</p>
          </div>
          <ScorePanel score={game.score} status={status} onRestart={restartGame} />
        </header>
        <GameBoard board={game.board} />
      </section>
    </main>
  )
}

export default App

